External Knowledge:
- 'champion drivers' refers to drivers who have won at least one race;
- 'quickest average speeds' refers to the drivers with the lowest average lap times;
- 'sunny days' refers to races that took place in sunny or partly cloudy weather conditions.

sql:
SELECT driver_name
FROM drivers
WHERE driver_id IN (
  SELECT DISTINCT winner_driver_id
  FROM races
);

SELECT total_races
FROM driver_career_stats
WHERE driver_id = 1;

SELECT COUNT(incident_id) AS incident_count
FROM race_incidents
WHERE driver_id = 0;

SELECT race_id
FROM fan_engagement
WHERE trackside_attendance = (SELECT MAX(trackside_attendance) FROM fan_engagement);

external_knowledge:
; Season in the context of racing typically refers to a specific year or period in which a series of races take place; 
; The status of a race being 'completed' means that the race has finished normally without any disruptions or interruptions; 
; A driver winning more than one race implies they have achieved multiple victories.

sql:
SELECT grand_prix
FROM races
WHERE race_date = '2005-03-06';

SELECT grand_prix
FROM races
ORDER BY grand_prix;

SELECT AVG(temperature_celsius) AS average_rainy_temperature
FROM track_conditions
WHERE weather = 'Rainy';
